import{_ as a,o as e,c as r,ag as l}from"./chunks/framework.DEs8X8sU.js";const u=JSON.parse('{"title":"スマレジ連携","description":"","frontmatter":{"title":"スマレジ連携"},"headers":[],"relativePath":"tenant/22-smaregi-full.md","filePath":"tenant/22-smaregi-full.md"}'),i={name:"tenant/22-smaregi-full.md"};function d(o,t,n,h,s,c){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="_22-スマレジ連携" tabindex="-1">22. スマレジ連携 <a class="header-anchor" href="#_22-スマレジ連携" aria-label="Permalink to &quot;22. スマレジ連携&quot;">​</a></h1><p>スマレジ連携では、POSLAとスマレジの店舗・商品・売上データを連携します。既存のPOS運用を残しながらPOSLAを導入する店舗で利用します。</p><h2 id="連携前に確認すること" tabindex="-1">連携前に確認すること <a class="header-anchor" href="#連携前に確認すること" aria-label="Permalink to &quot;連携前に確認すること&quot;">​</a></h2><ul><li>スマレジ側の契約と管理権限</li><li>連携する店舗の対応関係</li><li>商品名、カテゴリ、価格の整理</li><li>どちらを正として運用するか</li><li>営業中に同期作業を行わない運用</li></ul><h2 id="店舗マッピング" tabindex="-1">店舗マッピング <a class="header-anchor" href="#店舗マッピング" aria-label="Permalink to &quot;店舗マッピング&quot;">​</a></h2><p>POSLAの店舗とスマレジの店舗を対応付けます。対応がずれると、売上や商品が別店舗として扱われるため、必ず確認してください。</p><h2 id="商品連携" tabindex="-1">商品連携 <a class="header-anchor" href="#商品連携" aria-label="Permalink to &quot;商品連携&quot;">​</a></h2><p>商品名、価格、カテゴリを連携します。連携後は、POSLAとスマレジのどちらで編集するかを店舗内で統一してください。</p><h2 id="売上連携" tabindex="-1">売上連携 <a class="header-anchor" href="#売上連携" aria-label="Permalink to &quot;売上連携&quot;">​</a></h2><p>売上連携を利用する場合は、会計タイミング、取消、返金の扱いを確認してください。日報や会計処理に影響するため、テスト期間を設けることを推奨します。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>店舗が対応しない</td><td>店舗マッピングを確認してください。</td></tr><tr><td>商品が重複する</td><td>商品名、商品コード、連携方向を確認してください。</td></tr><tr><td>売上が合わない</td><td>期間、会計状態、返金、取消を確認してください。</td></tr><tr><td>連携を止めたい</td><td>POSLAサポートへご相談ください。</td></tr></tbody></table>',12)])])}const m=a(i,[["render",d]]);export{u as __pageData,m as default};
